import{_ as t,o,c as r,a2 as n}from"./chunks/framework.CHeM0PsO.js";const g=JSON.parse('{"title":"Security","description":"","frontmatter":{"docSection":"architecture-security","docType":"reference","audiences":["user","operator","app-developer","contributor"]},"headers":[],"relativePath":"security.md","filePath":"security.md"}'),s={name:"security.md"};function a(i,e,d,l,c,h){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><p>This document describes Sovereign&#39;s <strong>security posture</strong> — the threat model, the hardening that ships in v1, and a checklist for self-hosters. It complements <a href="https://github.com/sovereignfs/sovereign/blob/main/SECURITY.md" target="_blank" rel="noreferrer"><code>SECURITY.md</code></a> (vulnerability disclosure) and implements <a href="./rfcs/0008-security-encryption-architecture.html">RFC 0008</a> / SRS §3.17.</p><p>Sovereign is <strong>self-hosted and privacy-first</strong>: you run it, you own the data.</p><h2 id="no-telemetry" tabindex="-1">No telemetry <a class="header-anchor" href="#no-telemetry" aria-label="Permalink to &quot;No telemetry&quot;">​</a></h2><p>Sovereign sends <strong>no analytics, telemetry, or usage data</strong> anywhere. There is no outbound &quot;phone home&quot;, no third-party scripts, and no tracking. The only network calls a deployment makes are the ones you configure: the database, the SMTP server (if email is enabled), and the browser ↔ your instance. This is a guarantee, not a default you can toggle.</p><h2 id="logging-and-telemetry" tabindex="-1">Logging and telemetry <a class="header-anchor" href="#logging-and-telemetry" aria-label="Permalink to &quot;Logging and telemetry&quot;">​</a></h2><p>Sovereign&#39;s structured logger (RFC 0020) writes newline-delimited JSON to the process&#39;s own <strong>stdout/stderr</strong> — controlled by the <code>LOG_LEVEL</code> env var (<code>warn</code> by default). No log data is sent to any third party. Operators read logs via <code>docker logs</code>, <code>journalctl</code>, or their own log aggregator on the same host.</p><p>This is <strong>logging, not telemetry</strong>: everything stays on the operator&#39;s infrastructure. The no-telemetry guarantee is intact — the distinction is where the data goes, not whether it exists.</p><h2 id="production-dev-mode-isolation" tabindex="-1">Production dev-mode isolation <a class="header-anchor" href="#production-dev-mode-isolation" aria-label="Permalink to &quot;Production dev-mode isolation&quot;">​</a></h2><p>The optional <a href="./self-hosting.html#production-dev-mode-rfc-0020">production dev-mode</a> feature routes platform database reads and writes for a single request to a mock database, leaving all other concurrent requests unaffected. The isolation properties that make this safe to run on a live instance:</p><ul><li><strong>Off unless explicitly enabled.</strong> <code>SOVEREIGN_DEV_MODE_ENABLED</code> must be <code>true</code>; without it the <code>X-Sovereign-Dev-Mode-Secret</code> header is silently ignored.</li><li><strong>Secret-gated per request.</strong> Switching to the mock DB requires both a valid session cookie (authenticated caller) and the <code>SOVEREIGN_DEV_MODE_SECRET</code> header.</li><li><strong>Per-request, never global.</strong> The mock client is selected inside <code>getPlatformDb()</code> by reading the forwarded <code>x-sovereign-dev-mode</code> request header for that request&#39;s Next.js context only. A concurrent real-user request with no such header sees the production database as normal.</li><li><strong>Hard isolation between clients.</strong> The mock DB is a separate Drizzle <code>createClient()</code> instance. There is no code path from a dev-mode request back to the production <code>PlatformDb</code> singleton.</li><li><strong>Audited.</strong> Every activation is logged as a JSON line (level <code>info</code>) to server stdout, including the user ID and path, so operators can review usage via <code>docker logs</code>.</li></ul><h2 id="threat-model" tabindex="-1">Threat model <a class="header-anchor" href="#threat-model" aria-label="Permalink to &quot;Threat model&quot;">​</a></h2><p>Security controls are only meaningful against a stated adversary. <strong>Assets:</strong> the identity database (<code>auth.db</code>), the platform database (<code>sovereign.db</code>), plugin data, avatars/blobs, backups, secrets, and live sessions.</p><table tabindex="0"><thead><tr><th>Threat</th><th>Addressed by</th><th>Ships in</th><th>Residual risk</th></tr></thead><tbody><tr><td>Network sniffing / MITM</td><td>Transport: TLS/HSTS at the edge, Postgres SSL</td><td><strong>v1</strong></td><td>Endpoint compromise.</td></tr><tr><td>XSS / injected scripts</td><td>Strict nonce-based CSP + security headers</td><td><strong>v1</strong></td><td>A bug that echoes a valid nonce.</td></tr><tr><td>Clickjacking</td><td><code>X-Frame-Options: DENY</code> + <code>frame-ancestors &#39;none&#39;</code></td><td><strong>v1</strong></td><td>—</td></tr><tr><td>Stolen or guessed password</td><td>TOTP / passkey second factor (opt-in per user)</td><td><strong>v1</strong></td><td>Users who haven&#39;t enrolled MFA have password-only auth.</td></tr><tr><td>Forged session cookie</td><td>HMAC-signed cookie cache; Argon2id passwords (better-auth)</td><td><strong>v1</strong></td><td>Stolen live cookie from a compromised device.</td></tr><tr><td>Compromised / curious plugin</td><td>SDK boundary (plugins can&#39;t import runtime internals)</td><td><strong>v1</strong></td><td>A plugin still sees its own users&#39; data.</td></tr><tr><td>Stolen disk / leaked backup / VPS snapshot</td><td><strong>Opt-in SQLite at-rest encryption</strong> (RFC 0071, <code>SOVEREIGN_DB_ENCRYPTION_KEY</code>) for <code>sovereign.db</code>/<code>auth.db</code>/isolated plugin DBs; host-level disk encryption for everything else (Postgres, avatars/blobs); full envelope/field-level at-rest post-v1 (Task 8.5)</td><td><strong>v1 (opt-in, SQLite)</strong> / post-v1 (rest)</td><td>Off by default — without it enabled, rely on host-level disk encryption. Even enabled, server-held keys never defend against a curious operator or RCE (see the client-side row below for that).</td></tr><tr><td>Curious/malicious host or hosting provider</td><td>Field-level encryption; opt-in client-side encryption (RFC 0060), adopted today by <strong>Account</strong> (the encryption profile itself) and <strong>Sovereign Wallet</strong> (card/document contents) only</td><td><strong>v1 (opt-in, 2 plugins)</strong> / post-v1 (field-level)</td><td>Everything outside those two plugins&#39; encrypted fields — which is the large majority of platform and plugin data — still relies on host-level protection in v1.</td></tr><tr><td>RCE / compromised server process</td><td>Client-side encryption (RFC 0060) for the specific objects Account/Wallet protect this way</td><td><strong>v1 (opt-in, 2 plugins)</strong></td><td>Data not passed through client-side encryption — i.e. nearly everything except Wallet&#39;s card/document fields — is still readable by an attacker with code execution.</td></tr></tbody></table><p><strong>Honest framing.</strong> v1 ships Tiers 0–1 of RFC 0008 (hardening + transport) plus Tier 4 (client-side/zero-knowledge encryption, RFC 0060) as an <strong>opt-in capability</strong> the SDK makes available to any plugin — but only two plugins have actually adopted it so far: <strong>Account</strong> (its own encryption-profile setup/ recovery UX) and <strong>Sovereign Wallet</strong> (card metadata and ID/document images). For the fields those two plugins chose to encrypt, the runtime and server-side plugin code can never decrypt them, even with full server access. This is <strong>not a blanket guarantee</strong> and should not be read as &quot;Sovereign has client-side encryption&quot; in the general sense: every other plugin (Tasks, Ledger, Docs, PlainWrite, HealthLog, Shopper, Tally, TriText) currently stores its data with no client-side or at-rest protection, and most platform data overall is <strong>not</strong> encrypted at rest by default — anyone who can read the server&#39;s disk or a raw backup can still read the bulk of it, including all non-Wallet plugin data. Protect the host accordingly (see the checklist). At-rest and field-level encryption for the rest of the data model are specified and deferred to Task 1.0.1. Extending Tier 4 to another plugin is a per-plugin engineering decision — most plugins&#39; core functionality depends on server-side search, aggregation, or cross-user sharing that ciphertext-only storage would break (see the per-plugin sensitivity assessment referenced in the RFC 0060 adoption notes) — not something that broadens automatically.</p><h2 id="what-v1-enforces" tabindex="-1">What v1 enforces <a class="header-anchor" href="#what-v1-enforces" aria-label="Permalink to &quot;What v1 enforces&quot;">​</a></h2><ul><li><strong>Security headers on every response</strong> (both the runtime and the auth app): <ul><li><code>Content-Security-Policy</code> — strict and <strong>nonce-based</strong>: inline scripts run only with a per-request nonce (set in middleware); no <code>&#39;unsafe-inline&#39;</code> for scripts. <code>object-src &#39;none&#39;</code>, <code>base-uri &#39;self&#39;</code>, <code>frame-ancestors &#39;none&#39;</code>.</li><li><code>Strict-Transport-Security</code> (production only) — <code>max-age</code> 2 years, <code>includeSubDomains; preload</code>.</li><li><code>X-Frame-Options: DENY</code>, <code>X-Content-Type-Options: nosniff</code>, <code>Referrer-Policy: strict-origin-when-cross-origin</code>, <code>Permissions-Policy</code> (camera/microphone/geolocation/topics disabled).</li></ul></li><li><strong>No secrets with defaults.</strong> <code>AUTH_SECRET</code> / <code>SOVEREIGN_AUTH_SECRET</code>, <code>SOVEREIGN_ADMIN_KEY</code>, and vault encryption keys have no plaintext fallback. Features that require them fail closed when unset.</li><li><strong>Session cookies</strong> are <code>httpOnly</code>; the signed <code>session_data</code> cache cookie is HMAC-verified offline and carries <code>Secure</code> in production (<code>__Secure-</code> prefix).</li><li><strong>Transport:</strong> Postgres connects over TLS when the connection string sets <code>sslmode</code> (see below); the public edge must terminate TLS with HSTS.</li><li><strong>Login rate limiting</strong> is active in all environments (dev + production): the auth server enforces 3 sign-in attempts per 10 seconds per IP address and 3 password-reset requests per 60 seconds per IP (via better-auth&#39;s built-in per-path rate limiter). Responses above the limit return <code>429 Too Many Requests</code> with an <code>X-Retry-After</code> header. Rate limiting is stored in-memory per process (sufficient for single-instance deployments); a shared secondary storage (e.g. Redis) would be needed for multi-instance setups.</li><li><strong>Email verification is required by default</strong> (<code>AUTH_REQUIRE_EMAIL_VERIFICATION=true</code>). A new account must click an emailed link before it can sign in; registration does not grant a session until then. Operators can disable this (<code>AUTH_REQUIRE_EMAIL_VERIFICATION=false</code>) for air-gapped/internal deployments. Accounts that existed before this shipped are grandfathered automatically — the requirement only applies to new registrations.</li><li><strong>Console-managed SMTP settings (platform:owner only)</strong>: an owner can view and change SMTP host/port/user/password/from-address from Console → Settings, with changes taking effect immediately (no restart). The password is encrypted at rest with the same AES-256-GCM scheme (<code>SOVEREIGN_VAULT_KEY</code>) used by the plugin secret vault — never stored in plaintext, never logged, never returned to the client after saving (the form shows only whether a password is set, not its value). Non-owners see the current settings read-only and cannot save or send a test email.</li><li><strong>Client-side encryption (RFC 0060) has no operator recovery path, by design.</strong> A user unlocks their Client Master Key with a recorded recovery secret or an already-enrolled device — the server never holds a plaintext copy or an escrow key. <strong>Resetting a user&#39;s password does not recover their encrypted data</strong>; a lost recovery secret plus every enrolled device being lost means that data is permanently unrecoverable, for anyone, including the operator. Account deletion removes all client-side encryption material (profile, recovery wrapper, device enrollments) unconditionally — this is always safe, since none of it is ever plaintext. Account export includes this same wrapped material (still ciphertext-only) so a user&#39;s ability to unlock their data can travel with a data export/migration, provided they still have their recovery secret.</li></ul><h2 id="self-hoster-hardening-checklist" tabindex="-1">Self-hoster hardening checklist <a class="header-anchor" href="#self-hoster-hardening-checklist" aria-label="Permalink to &quot;Self-hoster hardening checklist&quot;">​</a></h2><ul><li>[ ] <strong>Terminate TLS at a reverse proxy</strong> (Caddy/nginx/Traefik) and redirect HTTP → HTTPS. See <a href="./self-hosting.html#reverse-proxy">self-hosting.md</a>. HSTS is emitted automatically by the apps in production.</li><li>[ ] <strong>Generate strong secrets</strong> (<code>openssl rand -base64 32</code>) for <code>AUTH_SECRET</code> and <code>SOVEREIGN_ADMIN_KEY</code>; never reuse or commit them.</li><li>[ ] <strong>Encrypt the host disk / volume</strong> — nothing is encrypted at rest by default, so this is your baseline protection for a stolen disk or snapshot. For SQLite deployments, an opt-in, single-key at-rest option is available — see <a href="./self-hosting.html#sqlite-at-rest-encryption-rfc-0071">SQLite at-rest encryption</a> (RFC 0071, <code>SOVEREIGN_DB_ENCRYPTION_KEY</code>). Postgres has no equivalent; host-level encryption remains the only protection there. Either way, back up the encryption key separately from the data.</li><li>[ ] <strong>Use Postgres over TLS</strong> for non-local databases: add <code>?sslmode=require</code> (or <code>verify-full</code> with a CA) to <code>DATABASE_URL</code> / <code>AUTH_DATABASE_URL</code>.</li><li>[ ] <strong>Enable MFA for all admin accounts</strong> — enroll TOTP or a passkey from Account → Security. MFA is opt-in; admins are not automatically required to use it in v1. Until mandatory-MFA enforcement lands, treat admin enrollment as a manual policy step.</li><li>[ ] <strong>Restrict network exposure</strong> — only the reverse proxy should be public; keep the auth server, database, and Mailpit on the internal network.</li><li>[ ] <strong>Configure <code>SMTP_HOST</code></strong> if you keep <code>AUTH_REQUIRE_EMAIL_VERIFICATION</code> at its default (<code>true</code>) — without SMTP, new registrations fail closed rather than issuing an unverifiable account.</li><li>[ ] <strong>Keep backups encrypted and off-host</strong>, and test restores.</li><li>[ ] <strong>Update regularly</strong> and watch the repository&#39;s security advisories.</li></ul><h2 id="reporting-a-vulnerability" tabindex="-1">Reporting a vulnerability <a class="header-anchor" href="#reporting-a-vulnerability" aria-label="Permalink to &quot;Reporting a vulnerability&quot;">​</a></h2><p>See <a href="https://github.com/sovereignfs/sovereign/blob/main/SECURITY.md" target="_blank" rel="noreferrer"><code>SECURITY.md</code></a>. Please do not file public issues for security reports.</p>',21)])])}const p=t(s,[["render",a]]);export{g as __pageData,p as default};
